import React from 'react';
import { motion } from 'framer-motion';

export default function Navbar() {
  return (
    <motion.nav
      className="text-white shadow-[0_2px_8px_rgba(0,0,0,0.08)] sticky top-0 z-50"
      style={{ background: 'linear-gradient(to right, #1F7A63, #125240)' }}
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
    >
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <motion.div
            className="flex-shrink-0"
            whileHover={{ scale: 1.05 }}
          >
            <div className="flex items-center gap-2">
              <div className="rounded-lg p-2 font-bold text-lg" style={{ backgroundColor: '#F4A261', color: '#1F7A63' }}>
                SS
              </div>
              <span className="font-bold text-xl hidden sm:inline">
                Subscription Surgeon
              </span>
              <span className="font-bold text-xl sm:hidden">
                Surgeon
              </span>
            </div>
          </motion.div>

          <div className="hidden md:block text-sm opacity-90">
            Manage subscriptions like a pro
          </div>
        </div>
      </div>
    </motion.nav>
  );
}
